import { 
  collection, getDocs, doc, getDoc, setDoc, updateDoc, addDoc, 
  query, where, orderBy, deleteDoc, Timestamp, writeBatch, onSnapshot 
} from "firebase/firestore";
import { 
  signInWithPopup, signOut, onAuthStateChanged 
} from "firebase/auth";
import { 
  ref, uploadBytes, getDownloadURL, deleteObject 
} from "firebase/storage";
import { db, auth, googleProvider, storage } from "./firebaseConfig";
import { 
  User, Document, DocState, DocHistory, UserRole, DocFile, 
  DocType, FullHierarchy, Notification, UserHierarchy, ProcessNode, Referent 
} from "../types";
import { 
  STATE_CONFIG, INITIAL_DATA_LOAD, NAME_TO_ID_MAP, REQUIRED_DOCS_MATRIX 
} from "../constants";

// --- Helpers ---
const determineStateFromVersion = (version: string): { state: DocState, progress: number } => {
    const v = (version || '').trim();
    if (!v || v === '-' || v === '0') return { state: DocState.NOT_STARTED, progress: 0 };
    if (v === '0.0') return { state: DocState.INITIATED, progress: 10 };
    if (v.endsWith('ACG')) return { state: DocState.APPROVED, progress: 100 };
    if (/^v1\.\d+\.\d+AR$/.test(v)) return { state: DocState.CONTROL_REVIEW, progress: 90 };
    if (/^v1\.\d+AR$/.test(v)) return { state: DocState.SENT_TO_CONTROL, progress: 90 };
    if (/^v1\.\d+\.\d+$/.test(v)) return { state: DocState.REFERENT_REVIEW, progress: 80 };
    if (/^v1\.\d+$/.test(v)) return { state: DocState.SENT_TO_REFERENT, progress: 80 };
    if (v.startsWith('v0.')) return { state: DocState.INTERNAL_REVIEW, progress: 60 };
    if (/^\d+\./.test(v)) return { state: DocState.IN_PROCESS, progress: 30 };
    return { state: DocState.IN_PROCESS, progress: 30 };
};

export const normalizeHeader = (header: string): string => {
    if (!header) return '';
    return header.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/^"|"$/g, ''); 
};

export const generateMatrixId = (project: string, micro: string): string => {
    const p = normalizeHeader(project).replace(/[^A-Z0-9]/g, '').substring(0, 10);
    const m = normalizeHeader(micro).replace(/[^A-Z0-9]+/g, '_').substring(0, 60); 
    return `MTX_${p}_${m}`;
};

// --- FIX: Added helper to delete a collection in batches to avoid Firestore write limits ---
const deleteCollectionInBatches = async (collectionName: string) => {
    const q = query(collection(db, collectionName));
    const snapshot = await getDocs(q);
    let batch = writeBatch(db);
    let count = 0;
    for (const docSnap of snapshot.docs) {
        batch.delete(docSnap.ref);
        count++;
        if (count >= 400) {
            await batch.commit();
            batch = writeBatch(db);
            count = 0;
        }
    }
    if (count > 0) await batch.commit();
};

// --- FIX: Added helper to find user IDs from a CSV string based on name, email or nickname ---
const findUserIdsFromCSV = (allUsers: User[], rawString: string): string[] => {
    if (!rawString) return [];
    const searchTerms = rawString.split(/[;,]/).map(s => s.trim().toLowerCase());
    const foundIds: string[] = [];
    searchTerms.forEach(term => {
        if (!term) return;
        const match = allUsers.find(u => 
            u.name.toLowerCase().includes(term) || 
            u.email.toLowerCase().includes(term) ||
            (u.nickname && u.nickname.toLowerCase().includes(term))
        );
        if (match) foundIds.push(match.id);
    });
    return Array.from(new Set(foundIds));
};

export const ReferentService = {
  getAll: async (): Promise<Referent[]> => {
    const q = query(collection(db, "referents"), orderBy("name"));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({ id: d.id, ...d.data() } as Referent));
  },
  create: async (data: Omit<Referent, 'id'>): Promise<Referent> => {
    const docRef = await addDoc(collection(db, "referents"), data);
    return { id: docRef.id, ...data };
  },
  update: async (id: string, data: Partial<Referent>): Promise<void> => {
    const ref = doc(db, "referents", id);
    await updateDoc(ref, data);
  },
  delete: async (id: string): Promise<void> => {
    await deleteDoc(doc(db, "referents", id));
  }
};

export const NotificationService = {
    create: async (userId: string, docId: string, type: Notification['type'], title: string, message: string, actorName: string) => {
        try {
            const notif: Omit<Notification, 'id'> = {
                userId, documentId: docId, type, title, message, isRead: false,
                timestamp: new Date().toISOString(), actorName
            };
            await addDoc(collection(db, "notifications"), notif);
        } catch (e) { console.error(e); }
    },
    getByUser: async (userId: string): Promise<Notification[]> => {
        const q = query(collection(db, "notifications"), where("userId", "==", userId));
        const snapshot = await getDocs(q);
        return snapshot.docs.map(d => ({ id: d.id, ...d.data() } as Notification));
    },
    subscribeToUnreadCount: (userId: string, callback: (count: number) => void) => {
        const q = query(collection(db, "notifications"), where("userId", "==", userId), where("isRead", "==", false));
        return onSnapshot(q, (snapshot) => callback(snapshot.size));
    },
    markAsRead: async (notifId: string) => {
        await updateDoc(doc(db, "notifications", notifId), { isRead: true });
    },
    markAllAsRead: async (userId: string) => {
        const q = query(collection(db, "notifications"), where("userId", "==", userId), where("isRead", "==", false));
        const snapshot = await getDocs(q);
        const batch = writeBatch(db);
        snapshot.docs.forEach(d => batch.update(d.ref, { isRead: true }));
        await batch.commit();
    }
};

export const UserService = {
  getAll: async (): Promise<User[]> => {
    const q = query(collection(db, "users"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, active: true, ...doc.data() } as User));
  },
  update: async (id: string, userData: Partial<User>): Promise<User> => {
    const userRef = doc(db, "users", id);
    await updateDoc(userRef, userData);
    const updatedSnap = await getDoc(userRef);
    return updatedSnap.data() as User;
  },
  toggleActiveStatus: async (id: string, currentStatus: boolean): Promise<void> => {
    await updateDoc(doc(db, "users", id), { active: !currentStatus });
  },
  create: async (userData: User): Promise<User> => {
      await setDoc(doc(db, "users", userData.id), { ...userData, active: userData.active ?? true });
      return userData;
  },
  delete: async (id: string) => { await deleteDoc(doc(db, "users", id)); },
  migrateLegacyReferences: async (oldId: string, newId: string) => {
      const qMatrix = query(collection(db, "process_matrix"), where("assignees", "array-contains", oldId));
      const snapMatrix = await getDocs(qMatrix);
      const batch = writeBatch(db);
      snapMatrix.docs.forEach(d => {
          const newAssignees = (d.data().assignees || []).map((id: string) => id === oldId ? newId : id);
          batch.update(d.ref, { assignees: newAssignees });
      });
      await batch.commit();
  }
};

export const HistoryService = {
  getHistory: async (docId: string): Promise<DocHistory[]> => {
    const q = query(collection(db, "history"), where("documentId", "==", docId));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => doc.data() as DocHistory).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  },
  getAll: async (): Promise<DocHistory[]> => {
    const q = query(collection(db, "history"), orderBy("timestamp", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => doc.data() as DocHistory);
  },
  log: async (docId: string, user: User, action: string, prev: DocState, next: DocState, comment: string) => {
    const newEntry: DocHistory = { id: `hist-${Date.now()}`, documentId: docId, userId: user.id, userName: user.name, action, previousState: prev, newState: next, comment, timestamp: new Date().toISOString() };
    await addDoc(collection(db, "history"), newEntry);
  }
};

export const DocumentService = {
  getAll: async (): Promise<Document[]> => {
    const q = query(collection(db, "documents"), orderBy("updatedAt", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Document));
  },
  getById: async (id: string): Promise<Document | null> => {
    const docRef = doc(db, "documents", id);
    const docSnap = await getDoc(docRef);
    return docSnap.exists() ? ({ id: docSnap.id, ...docSnap.data() } as Document) : null;
  },
  create: async (title: string, description: string, author: User, initialState?: DocState, initialVersion?: string, initialProgress?: number, file?: File, hierarchy?: any): Promise<Document> => {
    const state = initialState || DocState.INITIATED;
    const isSubmission = state === DocState.INTERNAL_REVIEW || state === DocState.SENT_TO_REFERENT || state === DocState.SENT_TO_CONTROL;
    let uploadedFiles: DocFile[] = [];
    const mergedAssignees = Array.from(new Set([...(hierarchy?.assignees || []), author.id]));
    const newDocData: Omit<Document, 'id'> = {
      title, description, authorId: author.id, authorName: author.name, assignedTo: author.id, assignees: mergedAssignees, state, version: initialVersion || '0.0', progress: initialProgress || 10, hasPendingRequest: isSubmission, files: uploadedFiles, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), project: hierarchy?.project, macroprocess: hierarchy?.macro, process: hierarchy?.process, microprocess: hierarchy?.micro, docType: hierarchy?.docType
    };
    const docRef = await addDoc(collection(db, "documents"), newDocData);
    await HistoryService.log(docRef.id, author, 'Creación', DocState.NOT_STARTED, state, `Creado v${initialVersion}`);
    return { id: docRef.id, ...newDocData } as Document;
  },
  delete: async (id: string) => { await deleteDoc(doc(db, "documents", id)); },
  transitionState: async (docId: string, user: User, action: any, comment: string, file?: File, customVersion?: string): Promise<void> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) throw new Error("Doc not found");
      const currentDoc = docSnap.data() as Document;
      let newState = currentDoc.state;
      let newVersion = currentDoc.version;
      let hasPending = currentDoc.hasPendingRequest;
      if (customVersion) {
        newVersion = customVersion;
        newState = determineStateFromVersion(customVersion).state;
      }
      if (action === 'APPROVE') hasPending = false;
      else if (action === 'REJECT') { hasPending = false; newState = determineStateFromVersion(newVersion).state; }
      else if (action === 'REQUEST_APPROVAL') hasPending = true;
      await updateDoc(docRef, { state: newState, version: newVersion, hasPendingRequest: hasPending, updatedAt: new Date().toISOString() });
      await HistoryService.log(docId, user, action, currentDoc.state, newState, comment);
  }
};

export const HierarchyService = {
  getFullHierarchy: async (): Promise<FullHierarchy> => {
    const q = query(collection(db, "process_matrix"));
    const snapshot = await getDocs(q);
    const hierarchy: FullHierarchy = {};
    snapshot.docs.forEach(doc => {
      const data = doc.data();
      const proj = data.project;
      const macro = data.macroprocess || 'Sin Macroproceso';
      const process = data.process;
      const node: ProcessNode = { name: data.name, docId: doc.id, assignees: data.assignees || [], referentIds: data.referentIds || [], requiredTypes: data.requiredTypes || [], active: data.active !== false };
      if (!hierarchy[proj]) hierarchy[proj] = {};
      if (!hierarchy[proj][macro]) hierarchy[proj][macro] = {};
      if (!hierarchy[proj][macro][process]) hierarchy[proj][macro][process] = [];
      hierarchy[proj][macro][process].push(node);
    });
    return hierarchy;
  },
  getUserHierarchy: async (userId: string): Promise<UserHierarchy> => {
      const q = query(collection(db, "process_matrix"), where("assignees", "array-contains", userId));
      const snapshot = await getDocs(q);
      const hierarchy: UserHierarchy = {};
      snapshot.docs.forEach(doc => {
          const data = doc.data();
          if (data.active === false) return;
          const proj = data.project;
          const macro = data.macroprocess || 'Sin Macroproceso';
          const process = data.process;
          if (!hierarchy[proj]) hierarchy[proj] = {};
          if (!hierarchy[proj][macro]) hierarchy[proj][macro] = {};
          if (!hierarchy[proj][macro][process]) hierarchy[proj][macro][process] = [];
          hierarchy[proj][macro][process].push(data.name);
      });
      return hierarchy;
  },
  updateMatrixAssignment: async (docId: string, assignees: string[]) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, { assignees });
  },
  // Nuevo método para vincular referentes masivamente desde el mantenedor de referentes
  updateReferentLinks: async (referentId: string, selectedDocIds: string[]) => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);

      snapshot.docs.forEach(d => {
          const data = d.data();
          let referents = data.referentIds || [];
          const isSelected = selectedDocIds.includes(d.id);
          const hasReferent = referents.includes(referentId);

          if (isSelected && !hasReferent) {
              batch.update(d.ref, { referentIds: [...referents, referentId] });
          } else if (!isSelected && hasReferent) {
              batch.update(d.ref, { referentIds: referents.filter((id:string) => id !== referentId) });
          }
      });
      await batch.commit();
  },
  toggleRequiredType: async (docId: string, type: DocType) => {
      const ref = doc(db, "process_matrix", docId);
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const current = new Set(snap.data().requiredTypes || []);
          if (current.has(type)) current.delete(type); else current.add(type);
          await updateDoc(ref, { requiredTypes: Array.from(current) });
      }
  },
  addMicroprocess: async (project: string, macro: string, process: string, name: string, assignees: string[], requiredTypes: string[]) => {
      const id = generateMatrixId(project, name);
      await setDoc(doc(db, "process_matrix", id), { project, macroprocess: macro, process, name, assignees, referentIds: [], requiredTypes, active: true });
  },
  deleteMicroprocess: async (docId: string) => { await deleteDoc(doc(db, "process_matrix", docId)); },
  getRequiredTypesMap: async (): Promise<Record<string, DocType[]>> => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const map: Record<string, DocType[]> = {};
      snapshot.docs.forEach(d => {
          const data = d.data();
          const key = `${normalizeHeader(data.project)}|${normalizeHeader(data.name)}`;
          map[key] = data.requiredTypes || [];
      });
      return map;
  },
  toggleProcessStatus: async (docId: string, currentStatus: boolean) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, { active: !currentStatus });
  },
  deleteHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') {
          q = query(collection(db, "process_matrix"), where("project", "==", name));
      } else if (level === 'MACRO') {
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", name));
      } else { // PROCESS
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", name));
      }

      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
  },
  updateHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', oldName: string, newName: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') {
          q = query(collection(db, "process_matrix"), where("project", "==", oldName));
      } else if (level === 'MACRO') {
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", oldName));
      } else { // PROCESS
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", oldName));
      }
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => {
          const update: any = {};
          if (level === 'PROJECT') update.project = newName;
          else if (level === 'MACRO') update.macroprocess = newName;
          else update.process = newName;
          batch.update(d.ref, update);
      });
      await batch.commit();
  },
  moveMicroprocess: async (docId: string, targetProject: string, targetMacro: string, targetProcess: string) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, {
          project: targetProject,
          macroprocess: targetMacro,
          process: targetProcess
      });
  },
  seedDefaults: async () => {
      const batch = writeBatch(db);
      for (const row of REQUIRED_DOCS_MATRIX) {
           const [project, micro, asis, fce, pm, tobe] = row;
           const requiredTypes: string[] = [];
           if (asis) requiredTypes.push('AS IS'); if (fce) requiredTypes.push('FCE'); if (pm) requiredTypes.push('PM'); if (tobe) requiredTypes.push('TO BE');
           const id = generateMatrixId(project, micro);
           batch.set(doc(db, "process_matrix", id), { project, macroprocess: 'Macroproceso General', process: 'Proceso General', name: micro, assignees: [], referentIds: [], requiredTypes, active: true });
      }
      await batch.commit();
  }
};

export const DatabaseService = {
    exportData: async (): Promise<string> => {
        const collections = ['users', 'documents', 'history', 'process_matrix', 'notifications', 'referents'];
        const data: any = {};
        for (const colName of collections) {
            const snapshot = await getDocs(collection(db, colName));
            data[colName] = snapshot.docs.map(d => ({ _id: d.id, ...d.data() }));
        }
        return JSON.stringify(data, null, 2);
    },
    importData: async (jsonString: string) => {
        const data = JSON.parse(jsonString);
        for (const colName of Object.keys(data)) {
            await deleteCollectionInBatches(colName);
            const items = data[colName];
            let batch = writeBatch(db);
            let count = 0;
            for (const item of items) {
                const { _id, ...docData } = item;
                batch.set(doc(db, colName, _id), docData);
                count++;
                if (count >= 400) { await batch.commit(); batch = writeBatch(db); count = 0; }
            }
            if (count > 0) await batch.commit();
        }
    },
    fullSystemResetAndImport: async (rulesCSV: string, historyCSV: string, onProgress: (percent: number, status: string) => void): Promise<{ created: number, historyMatched: number }> => {
        onProgress(5, "Limpiando...");
        await deleteCollectionInBatches("documents"); await deleteCollectionInBatches("history"); await deleteCollectionInBatches("process_matrix"); await deleteCollectionInBatches("notifications");
        onProgress(10, "Reglas...");
        const rows = rulesCSV.split(/\r?\n/).filter(r => r.trim().length > 0);
        const headers = rows[0].split(/[;,]/).map(h => normalizeHeader(h));
        const idxProject = headers.findIndex(h => h.includes('PROYECTO'));
        const idxMacro = headers.findIndex(h => h.includes('MACRO'));
        const idxProcess = headers.findIndex(h => h === 'PROCESO');
        const idxMicro = headers.findIndex(h => h.includes('MICRO'));
        const idxAnalyst = headers.findIndex(h => h.includes('ANALISTA') || h.includes('RESPONSABLE'));
        const idxAsis = headers.findIndex(h => h.includes('ASIS') || h.includes('AS IS'));
        const idxFce = headers.findIndex(h => h.includes('FCE'));
        const idxPm = headers.findIndex(h => h.includes('PM'));
        const idxTobe = headers.findIndex(h => h.includes('TOBE') || h.includes('TO BE'));
        const allUsers = await UserService.getAll();
        let createdCount = 0;
        let batch = writeBatch(db);
        let opCount = 0;
        for (let i = 1; i < rows.length; i++) {
            const cols = rows[i].split(/[;,]/).map(c => c.trim());
            if (cols.length < 3) continue;
            const project = cols[idxProject] || 'GENERAL';
            const macro = cols[idxMacro] || 'General';
            const process = cols[idxProcess] || 'General';
            const micro = cols[idxMicro];
            if (!micro) continue;
            const assignees = findUserIdsFromCSV(allUsers, cols[idxAnalyst]);
            const requiredTypes: string[] = [];
            if (cols[idxAsis] === '1') requiredTypes.push('AS IS');
            if (cols[idxFce] === '1') requiredTypes.push('FCE');
            if (cols[idxPm] === '1') requiredTypes.push('PM');
            if (cols[idxTobe] === '1') requiredTypes.push('TO BE');
            const id = generateMatrixId(project, micro);
            const nodeData = { project, macroprocess: macro, process, name: micro, assignees, referentIds: [], requiredTypes, active: true };
            batch.set(doc(db, "process_matrix", id), nodeData);
            opCount++; createdCount++;
            if (opCount >= 400) { await batch.commit(); batch = writeBatch(db); opCount = 0; }
        }
        if (opCount > 0) await batch.commit();
        onProgress(100, "Finalizando...");
        return { created: createdCount, historyMatched: 0 };
    }
};

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area, LineChart, Line
} from 'recharts';
import { 
    TrendingUp, Users, AlertTriangle, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, User as UserIcon, ArrowRight, Target
} from 'lucide-react';

interface Props {
    user: User;
}

// Extends Document to handle "Virtual" documents (not yet created but required)
interface ReportDoc extends Document {
    isVirtual?: boolean;
    requiredType?: string;
}

// Color Map matching Dashboard
const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#e2e8f0', // Slate 200
    'En Proceso': '#3b82f6',  // Blue 500
    'En Revisión': '#a855f7', // Purple 500 (Mix of Referente/Control)
    'Rechazado': '#ef4444',   // Red 500
    'Aprobado': '#22c55e'     // Green 500
};

// Colores actualizados según la imagen de referencia (Azul, Salmón, Amarillo, Verde)
const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6', // Azul
    'FCE': '#f87171',   // Salmón / Rojo claro
    'PM': '#facc15',    // Amarillo
    'TO BE': '#22c55e'  // Verde
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    // --- DATA PROCESSING ---

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];

        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    const nodes = hierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ ...realDoc, macroprocess: macro, process: proc, project: proj, assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []), isVirtual: false });
                            } else {
                                unifiedList.push({ id: `virtual-${key}`, title: `${node.name} - ${type}`, description: 'Pendiente de inicio', project: proj, macroprocess: macro, process: proc, microprocess: node.name, docType: type as DocType, authorId: '', authorName: '', assignedTo: node.assignees?.[0] || '', assignees: node.assignees || [], state: DocState.NOT_STARTED, version: '-', progress: 0, files: [], createdAt: new Date().toISOString(), updatedAt: new Date(0).toISOString(), hasPendingRequest: false, isVirtual: true, requiredType: type });
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    const kpis = useMemo(() => {
        const approvedDocs = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const thirtyDaysAgo = new Date(); thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
        const isStalled = (d: ReportDoc) => !d.isVirtual && d.state !== DocState.NOT_STARTED && new Date(d.updatedAt) < thirtyDaysAgo;

        const internalStates = [DocState.INITIATED, DocState.IN_PROCESS, DocState.INTERNAL_REVIEW];
        const referentStates = [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW];
        const controlStates = [DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW];

        return { 
            total: filteredDocs.length, totalIds: filteredDocs.map(d => d.id),
            approved: approvedDocs.length, approvedIds: approvedDocs.map(d => d.id),
            stalledInternal: filteredDocs.filter(d => internalStates.includes(d.state) && isStalled(d)).length,
            stalledInternalIds: filteredDocs.filter(d => internalStates.includes(d.state) && isStalled(d)).map(d => d.id),
            stalledReferent: filteredDocs.filter(d => referentStates.includes(d.state) && isStalled(d)).length,
            stalledReferentIds: filteredDocs.filter(d => referentStates.includes(d.state) && isStalled(d)).map(d => d.id),
            stalledControl: filteredDocs.filter(d => controlStates.includes(d.state) && isStalled(d)).length,
            stalledControlIds: filteredDocs.filter(d => controlStates.includes(d.state) && isStalled(d)).map(d => d.id)
        };
    }, [filteredDocs]);

    const stateData = useMemo(() => {
        const counts: Record<string, number> = { 'No Iniciado': 0, 'En Proceso': 0, 'En Revisión': 0, 'Rechazado': 0, 'Aprobado': 0 };
        filteredDocs.forEach(d => {
            let key = 'En Proceso';
            if (d.state === DocState.NOT_STARTED) key = 'No Iniciado';
            else if (d.state === DocState.APPROVED) key = 'Aprobado';
            else if (d.state === DocState.REJECTED) key = 'Rechazado';
            else if ([DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.SENT_TO_CONTROL, DocState.REFERENT_REVIEW, DocState.CONTROL_REVIEW].includes(d.state)) key = 'En Revisión';
            counts[key] = (counts[key] || 0) + 1;
        });
        return Object.keys(counts).filter(k => counts[k] > 0).map(name => ({ name, value: counts[name] }));
    }, [filteredDocs]);

    const analystData = useMemo(() => {
        const stats: Record<string, { assigned: number, approved: number, inProgress: number }> = {};
        filteredDocs.forEach(d => {
            if (d.assignees) {
                d.assignees.forEach(uid => {
                    if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0, inProgress: 0 };
                    stats[uid].assigned += 1;
                    if (d.state === DocState.APPROVED) stats[uid].approved += 1;
                    else if (d.state !== DocState.NOT_STARTED) stats[uid].inProgress += 1;
                });
            }
        });
        return Object.keys(stats).map(uid => {
            const u = users.find(user => user.id === uid);
            return { name: u ? (u.nickname || u.name.split(' ')[0]) : 'Desc.', Requeridos: stats[uid].assigned, EnProceso: stats[uid].inProgress, Terminados: stats[uid].approved };
        }).sort((a, b) => b.Requeridos - a.Requeridos).slice(0, 10);
    }, [filteredDocs, users]);

    // Data for circular compliance gauges
    const typeComplianceData = useMemo(() => {
        const types: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];
        return types.map(type => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const total = docsOfType.length;
            const finished = docsOfType.filter(d => d.state === DocState.APPROVED).length;
            const percent = total > 0 ? Math.round((finished / total) * 100) : 0;
            return { type, total, finished, percent, color: TYPE_COLORS[type] };
        });
    }, [filteredDocs]);

    // EVOLUCIÓN MENSUAL: 12 meses móviles con desglose por tipo de documento
    const evolutionData = useMemo(() => {
        const monthsLabel = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
        const now = new Date();
        const twelveMonthsAgo = new Date();
        twelveMonthsAgo.setMonth(now.getMonth() - 11);
        twelveMonthsAgo.setDate(1);
        twelveMonthsAgo.setHours(0, 0, 0, 0);

        // Generar lista de los últimos 12 meses
        const periods: { key: string, label: string, 'AS IS': number, 'FCE': number, 'PM': number, 'TO BE': number }[] = [];
        for (let i = 0; i < 12; i++) {
            const d = new Date(twelveMonthsAgo);
            d.setMonth(twelveMonthsAgo.getMonth() + i);
            const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
            const label = `${monthsLabel[d.getMonth()]}-${String(d.getFullYear()).slice(-2)}`;
            periods.push({ key, label, 'AS IS': 0, 'FCE': 0, 'PM': 0, 'TO BE': 0 });
        }

        // Mapear historial filtrado por proyecto/analista
        const filteredDocIds = new Set(filteredDocs.map(d => d.id));
        const docTypeMap = new Map(filteredDocs.map(d => [d.id, d.docType]));

        history.forEach(h => {
            if (!filteredDocIds.has(h.documentId)) return;
            const hDate = new Date(h.timestamp);
            if (hDate < twelveMonthsAgo) return;

            const hKey = `${hDate.getFullYear()}-${String(hDate.getMonth() + 1).padStart(2, '0')}`;
            const type = docTypeMap.get(h.documentId);

            const period = periods.find(p => p.key === hKey);
            if (period && type && period[type] !== undefined) {
                period[type]++;
            }
        });

        return periods;
    }, [filteredDocs, history]);

    const availableProjects = useMemo(() => Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))), [unifiedData]);

    const goToDashboard = (ids: string[]) => navigate('/', { state: { filterIds: ids, fromReport: true } });

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Generando reporte...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2"><LayoutDashboard className="text-indigo-600" /> Reportes de Gestión</h1>
                    <p className="text-slate-500">Métricas basadas en la Matriz de Asignaciones (Universo Total).</p>
                </div>
                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px] border-r border-slate-100">
                        <option value="">Todos los Proyectos</option>
                        {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                    <div className="flex items-center gap-1 px-2">
                        <UserIcon size={14} className="text-slate-400" />
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px]">
                            <option value="">Todos los Analistas</option>
                            {users.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                </div>
            </div>

            {/* KPIs */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                <KPICard title="Total Requeridos" value={kpis.total} icon={FileText} color="indigo" sub="Universo Total" onClick={() => goToDashboard(kpis.totalIds)} canClick={kpis.total > 0} />
                <KPICard title="Interno > 30d" value={kpis.stalledInternal} icon={Clock} color="orange" sub="Sin avance reciente" onClick={() => goToDashboard(kpis.stalledInternalIds)} canClick={kpis.stalledInternal > 0} />
                <KPICard title="Referente > 30d" value={kpis.stalledReferent} icon={Clock} color="orange" sub="Sin avance reciente" onClick={() => goToDashboard(kpis.stalledReferentIds)} canClick={kpis.stalledReferent > 0} />
                <KPICard title="Control > 30d" value={kpis.stalledControl} icon={Clock} color="orange" sub="Sin avance reciente" onClick={() => goToDashboard(kpis.stalledControlIds)} canClick={kpis.stalledControl > 0} />
                <KPICard title="Terminados" value={kpis.approved} icon={CheckCircle} color="green" sub="100% Aprobados" onClick={() => goToDashboard(kpis.approvedIds)} canClick={kpis.approved > 0} />
            </div>

            {/* SECCIÓN 1: CUMPLIMIENTO POR TIPO (OCUPA TODO EL ANCHO ARRIBA) */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                    <Target size={16} /> Cumplimiento por Tipo de Documento
                </h3>
                <p className="text-xs text-slate-500 mb-8">Progreso de documentos terminados vs requeridos en el universo total.</p>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                    {typeComplianceData.map((item) => (
                        <div key={item.type} className="flex flex-col items-center">
                            <div className="relative w-28 h-28 mb-3">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={[
                                                { value: item.percent },
                                                { value: 100 - item.percent }
                                            ]}
                                            cx="50%"
                                            cy="50%"
                                            innerRadius={35}
                                            outerRadius={50}
                                            startAngle={90}
                                            endAngle={-270}
                                            dataKey="value"
                                            stroke="none"
                                        >
                                            <Cell key="progress" fill={item.color} />
                                            <Cell key="bg" fill="#f1f5f9" />
                                        </Pie>
                                    </PieChart>
                                </ResponsiveContainer>
                                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                                    <span className="text-lg font-extrabold text-slate-800">{item.percent}%</span>
                                </div>
                            </div>
                            <span className="text-xs font-bold text-slate-700 uppercase tracking-wider">{item.type}</span>
                            <span className="text-[10px] text-slate-400 mt-1">{item.finished} de {item.total}</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* SECCIÓN 2: ESTADOS Y ANALISTAS (POSICIÓN INTERMEDIA) */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-1 flex flex-col">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2"><Briefcase size={16} /> Estado del Universo</h3>
                    <p className="text-xs text-slate-500 mb-6">Distribución detallada por estado actual.</p>
                    <div className="flex-1 min-h-[250px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={stateData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                                    {stateData.map((entry, index) => <Cell key={`cell-${index}`} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} />)}
                                </Pie>
                                <Tooltip />
                                <Legend verticalAlign="bottom" height={36}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2"><Users size={16} /> Gestión por Analista</h3>
                    <p className="text-xs text-slate-500 mb-6">Comparativa: Requeridos vs. En Proceso vs. Terminados.</p>
                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={analystData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <Tooltip contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} cursor={{fill: '#f8fafc'}} />
                                <Legend />
                                <Bar dataKey="Requeridos" fill="#94a3b8" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="EnProceso" name="En Proceso" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="Terminados" fill="#22c55e" radius={[4, 4, 0, 0]} barSize={20} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

            {/* SECCIÓN 3: EVOLUCIÓN MENSUAL (ANCHO COMPLETO AL FINAL) */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2"><Clock size={16} /> Evolución Mensual</h3>
                <p className="text-xs text-slate-500 mb-6">Frecuencia de cambios de estado realizados en los últimos 12 meses móviles.</p>
                <div className="h-[350px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <LineChart data={evolutionData} margin={{ top: 20, right: 30, left: 0, bottom: 10 }}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                            <XAxis 
                                dataKey="label" 
                                tick={{ fontSize: 11, fill: '#64748b' }} 
                                axisLine={{ stroke: '#e2e8f0' }}
                                tickLine={false}
                            />
                            <YAxis 
                                tick={{ fontSize: 11, fill: '#64748b' }} 
                                axisLine={{ stroke: '#e2e8f0' }}
                                tickLine={false}
                            />
                            <Tooltip 
                                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                            />
                            <Legend verticalAlign="top" height={36} iconType="circle" wrapperStyle={{ fontSize: '12px', fontWeight: 'bold' }} />

                            <Line type="monotone" dataKey="AS IS" stroke={TYPE_COLORS['AS IS']} strokeWidth={3} dot={{ r: 4, fill: TYPE_COLORS['AS IS'] }} activeDot={{ r: 6 }} />
                            <Line type="monotone" dataKey="FCE" stroke={TYPE_COLORS['FCE']} strokeWidth={3} dot={{ r: 4, fill: TYPE_COLORS['FCE'] }} activeDot={{ r: 6 }} />
                            <Line type="monotone" dataKey="PM" stroke={TYPE_COLORS['PM']} strokeWidth={3} dot={{ r: 4, fill: TYPE_COLORS['PM'] }} activeDot={{ r: 6 }} />
                            <Line type="monotone" dataKey="TO BE" stroke={TYPE_COLORS['TO BE']} strokeWidth={3} dot={{ r: 4, fill: TYPE_COLORS['TO BE'] }} activeDot={{ r: 6 }} />
                        </LineChart>
                    </ResponsiveContainer>
                </div>
                <div className="mt-4 p-3 bg-slate-50 rounded-lg border border-slate-100 flex items-center gap-3">
                    <Info size={16} className="text-slate-400" />
                    <p className="text-[10px] text-slate-500 font-medium">Estadística basada en transacciones reales registradas en el sistema por tipo de documento durante el periodo móvil de 12 meses.</p>
                </div>
            </div>
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', blue: 'bg-blue-50 text-blue-600 border-blue-100', green: 'bg-green-50 text-green-600 border-green-100', orange: 'bg-orange-50 text-orange-600 border-orange-100', red: 'bg-red-50 text-red-600 border-red-100' };
    return (
        <div onClick={canClick ? onClick : undefined} className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} ${canClick ? 'cursor-pointer hover:shadow-md hover:ring-2 hover:ring-opacity-50 hover:ring-indigo-300 transition-all active:scale-95' : ''}`}>
            <div className="flex justify-between items-start mb-2"><span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span><Icon size={18} /></div>
            <div><span className="text-2xl font-bold">{value}</span><div className="flex justify-between items-center mt-1"><p className="text-[10px] opacity-80 font-medium">{sub}</p>{canClick && <ArrowRight size={12} className="opacity-60" />}</div></div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area, LineChart, Line
} from 'recharts';
import { 
    // Added Info to the import list below
    TrendingUp, Users, AlertTriangle, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, User as UserIcon, ArrowRight, Target, Info
} from 'lucide-react';

interface Props {
    user: User;
}

// Extends Document to handle "Virtual" documents (not yet created but required)
interface ReportDoc extends Document {
    isVirtual?: boolean;
    requiredType?: string;
}

// Color Map matching Dashboard
const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#e2e8f0', // Slate 200
    'En Proceso': '#3b82f6',  // Blue 500
    'En Revisión': '#a855f7', // Purple 500 (Mix of Referente/Control)
    'Rechazado': '#ef4444',   // Red 500
    'Aprobado': '#22c55e'     // Green 500
};

// Colores actualizados según la imagen de referencia (Azul, Salmón, Amarillo, Verde)
const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6', // Azul
    'FCE': '#f87171',   // Salmón / Rojo claro
    'PM': '#facc15',    // Amarillo
    'TO BE': '#22c55e'  // Verde
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    // --- DATA PROCESSING ---

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];

        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    const nodes = hierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ ...realDoc, macroprocess: macro, process: proc, project: proj, assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []), isVirtual: false });
                            } else {
                                unifiedList.push({ id: `virtual-${key}`, title: `${node.name} - ${type}`, description: 'Pendiente de inicio', project: proj, macroprocess: macro, process: proc, microprocess: node.name, docType: type as DocType, authorId: '', authorName: '', assignedTo: node.assignees?.[0] || '', assignees: node.assignees || [], state: DocState.NOT_STARTED, version: '-', progress: 0, files: [], createdAt: new Date().toISOString(), updatedAt: new Date(0).toISOString(), hasPendingRequest: false, isVirtual: true, requiredType: type });
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    const kpis = useMemo(() => {
        const approvedDocs = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const thirtyDaysAgo = new Date(); thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
        const isStalled = (d: ReportDoc) => !d.isVirtual && d.state !== DocState.NOT_STARTED && new Date(d.updatedAt) < thirtyDaysAgo;

        const internalStates = [DocState.INITIATED, DocState.IN_PROCESS, DocState.INTERNAL_REVIEW];
        const referentStates = [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW];
        const controlStates = [DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW];

        return { 
            total: filteredDocs.length, totalIds: filteredDocs.map(d => d.id),
            approved: approvedDocs.length, approvedIds: approvedDocs.map(d => d.id),
            stalledInternal: filteredDocs.filter(d => internalStates.includes(d.state) && isStalled(d)).length,
            stalledInternalIds: filteredDocs.filter(d => internalStates.includes(d.state) && isStalled(d)).map(d => d.id),
            stalledReferent: filteredDocs.filter(d => referentStates.includes(d.state) && isStalled(d)).length,
            stalledReferentIds: filteredDocs.filter(d => referentStates.includes(d.state) && isStalled(d)).map(d => d.id),
            stalledControl: filteredDocs.filter(d => controlStates.includes(d.state) && isStalled(d)).length,
            stalledControlIds: filteredDocs.filter(d => controlStates.includes(d.state) && isStalled(d)).map(d => d.id)
        };
    }, [filteredDocs]);

    const stateData = useMemo(() => {
        const counts: Record<string, number> = { 'No Iniciado': 0, 'En Proceso': 0, 'En Revisión': 0, 'Rechazado': 0, 'Aprobado': 0 };
        filteredDocs.forEach(d => {
            let key = 'En Proceso';
            if (d.state === DocState.NOT_STARTED) key = 'No Iniciado';
            else if (d.state === DocState.APPROVED) key = 'Aprobado';
            else if (d.state === DocState.REJECTED) key = 'Rechazado';
            else if ([DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.SENT_TO_CONTROL, DocState.REFERENT_REVIEW, DocState.CONTROL_REVIEW].includes(d.state)) key = 'En Revisión';
            counts[key] = (counts[key] || 0) + 1;
        });
        return Object.keys(counts).filter(k => counts[k] > 0).map(name => ({ name, value: counts[name] }));
    }, [filteredDocs]);

    const analystData = useMemo(() => {
        const stats: Record<string, { assigned: number, approved: number, inProgress: number }> = {};
        filteredDocs.forEach(d => {
            if (d.assignees) {
                d.assignees.forEach(uid => {
                    if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0, inProgress: 0 };
                    stats[uid].assigned += 1;
                    if (d.state === DocState.APPROVED) stats[uid].approved += 1;
                    else if (d.state !== DocState.NOT_STARTED) stats[uid].inProgress += 1;
                });
            }
        });
        return Object.keys(stats).map(uid => {
            const u = users.find(user => user.id === uid);
            return { name: u ? (u.nickname || u.name.split(' ')[0]) : 'Desc.', Requeridos: stats[uid].assigned, EnProceso: stats[uid].inProgress, Terminados: stats[uid].approved };
        }).sort((a, b) => b.Requeridos - a.Requeridos).slice(0, 10);
    }, [filteredDocs, users]);

    // Data for circular compliance gauges
    const typeComplianceData = useMemo(() => {
        const types: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];
        return types.map(type => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const total = docsOfType.length;
            const finished = docsOfType.filter(d => d.state === DocState.APPROVED).length;
            const percent = total > 0 ? Math.round((finished / total) * 100) : 0;
            return { type, total, finished, percent, color: TYPE_COLORS[type] };
        });
    }, [filteredDocs]);

    // EVOLUCIÓN MENSUAL: 12 meses móviles con desglose por tipo de documento
    const evolutionData = useMemo(() => {
        const monthsLabel = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
        const now = new Date();
        const twelveMonthsAgo = new Date();
        twelveMonthsAgo.setMonth(now.getMonth() - 11);
        twelveMonthsAgo.setDate(1);
        twelveMonthsAgo.setHours(0, 0, 0, 0);

        // Generar lista de los últimos 12 meses
        const periods: { key: string, label: string, 'AS IS': number, 'FCE': number, 'PM': number, 'TO BE': number }[] = [];
        for (let i = 0; i < 12; i++) {
            const d = new Date(twelveMonthsAgo);
            d.setMonth(twelveMonthsAgo.getMonth() + i);
            const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
            const label = `${monthsLabel[d.getMonth()]}-${String(d.getFullYear()).slice(-2)}`;
            periods.push({ key, label, 'AS IS': 0, 'FCE': 0, 'PM': 0, 'TO BE': 0 });
        }

        // Mapear historial filtrado por proyecto/analista
        const filteredDocIds = new Set(filteredDocs.map(d => d.id));
        // FIX: Explicitly typing docTypeMap to avoid 'unknown' index type error
        const docTypeMap = new Map<string, DocType | undefined>(filteredDocs.map(d => [d.id, d.docType]));

        history.forEach(h => {
            if (!filteredDocIds.has(h.documentId)) return;
            const hDate = new Date(h.timestamp);
            if (hDate < twelveMonthsAgo) return;

            const hKey = `${hDate.getFullYear()}-${String(hDate.getMonth() + 1).padStart(2, '0')}`;
            const type = docTypeMap.get(h.documentId);

            const period = periods.find(p => p.key === hKey);
            // FIX: Using cast to bypass 'unknown' and indexing issues in strict environments
            if (period && type && (period as any)[type] !== undefined) {
                (period as any)[type]++;
            }
        });

        return periods;
    }, [filteredDocs, history]);

    const availableProjects = useMemo(() => Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))), [unifiedData]);

    const goToDashboard = (ids: string[]) => navigate('/', { state: { filterIds: ids, fromReport: true } });

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Generando reporte...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2"><LayoutDashboard className="text-indigo-600" /> Reportes de Gestión</h1>
                    <p className="text-slate-500">Métricas basadas en la Matriz de Asignaciones (Universo Total).</p>
                </div>
                <div className="flex items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px] border-r border-slate-100">
                        <option value="">Todos los Proyectos</option>
                        {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                    <div className="flex items-center gap-1 px-2">
                        <UserIcon size={14} className="text-slate-400" />
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px]">
                            <option value="">Todos los Analistas</option>
                            {users.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                </div>
            </div>

            {/* KPIs */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                <KPICard title="Total Requeridos" value={kpis.total} icon={FileText} color="indigo" sub="Universo Total" onClick={() => goToDashboard(kpis.totalIds)} canClick={kpis.total > 0} />
                <KPICard title="Interno > 30d" value={kpis.stalledInternal} icon={Clock} color="orange" sub="Sin avance reciente" onClick={() => goToDashboard(kpis.stalledInternalIds)} canClick={kpis.stalledInternal > 0} />
                <KPICard title="Referente > 30d" value={kpis.stalledReferent} icon={Clock} color="orange" sub="Sin avance reciente" onClick={() => goToDashboard(kpis.stalledReferentIds)} canClick={kpis.stalledReferent > 0} />
                <KPICard title="Control > 30d" value={kpis.stalledControl} icon={Clock} color="orange" sub="Sin avance reciente" onClick={() => goToDashboard(kpis.stalledControlIds)} canClick={kpis.stalledControl > 0} />
                <KPICard title="Terminados" value={kpis.approved} icon={CheckCircle} color="green" sub="100% Aprobados" onClick={() => goToDashboard(kpis.approvedIds)} canClick={kpis.approved > 0} />
            </div>

            {/* SECCIÓN 1: CUMPLIMIENTO POR TIPO (OCUPA TODO EL ANCHO ARRIBA) */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                    <Target size={16} /> Cumplimiento por Tipo de Documento
                </h3>
                <p className="text-xs text-slate-500 mb-8">Progreso de documentos terminados vs requeridos en el universo total.</p>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                    {typeComplianceData.map((item) => (
                        <div key={item.type} className="flex flex-col items-center">
                            <div className="relative w-28 h-28 mb-3">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={[
                                                { value: item.percent },
                                                { value: 100 - item.percent }
                                            ]}
                                            cx="50%"
                                            cy="50%"
                                            innerRadius={35}
                                            outerRadius={50}
                                            startAngle={90}
                                            endAngle={-270}
                                            dataKey="value"
                                            stroke="none"
                                        >
                                            <Cell key="progress" fill={item.color} />
                                            <Cell key="bg" fill="#f1f5f9" />
                                        </Pie>
                                    </PieChart>
                                </ResponsiveContainer>
                                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                                    <span className="text-lg font-extrabold text-slate-800">{item.percent}%</span>
                                </div>
                            </div>
                            <span className="text-xs font-bold text-slate-700 uppercase tracking-wider">{item.type}</span>
                            <span className="text-[10px] text-slate-400 mt-1">{item.finished} de {item.total}</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* SECCIÓN 2: ESTADOS Y ANALISTAS (POSICIÓN INTERMEDIA) */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-1 flex flex-col">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2"><Briefcase size={16} /> Estado del Universo</h3>
                    <p className="text-xs text-slate-500 mb-6">Distribución detallada por estado actual.</p>
                    <div className="flex-1 min-h-[250px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={stateData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                                    {stateData.map((entry, index) => <Cell key={`cell-${index}`} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} />)}
                                </Pie>
                                <Tooltip />
                                <Legend verticalAlign="bottom" height={36}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2"><Users size={16} /> Gestión por Analista</h3>
                    <p className="text-xs text-slate-500 mb-6">Comparativa: Requeridos vs. En Proceso vs. Terminados.</p>
                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={analystData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
