                            <Tooltip 
                                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                            />
                            <Legend verticalAlign="top" height={36} iconType="circle" wrapperStyle={{ fontSize: '12px', fontWeight: 'bold' }} />

                            <Line type="monotone" dataKey="AS IS" stroke={TYPE_COLORS['AS IS']} strokeWidth={3} dot={{ r: 4, fill: TYPE_COLORS['AS IS'] }} activeDot={{ r: 6 }} />
                            <Line type="monotone" dataKey="FCE" stroke={TYPE_COLORS['FCE']} strokeWidth={3} dot={{ r: 4, fill: TYPE_COLORS['FCE'] }} activeDot={{ r: 6 }} />
                            <Line type="monotone" dataKey="PM" stroke={TYPE_COLORS['PM']} strokeWidth={3} dot={{ r: 4, fill: TYPE_COLORS['PM'] }} activeDot={{ r: 6 }} />
                            <Line type="monotone" dataKey="TO BE" stroke={TYPE_COLORS['TO BE']} strokeWidth={3} dot={{ r: 4, fill: TYPE_COLORS['TO BE'] }} activeDot={{ r: 6 }} />
