                    </ResponsiveContainer>
                </div>
                <div className="mt-4 p-3 bg-slate-50 rounded-lg border border-slate-100 flex items-center gap-3">
                    <Info size={16} className="text-slate-400" />
                    <p className="text-[10px] text-slate-500 font-medium">Estadística basada en transacciones reales registradas en el sistema por tipo de documento durante el periodo móvil de 12 meses.</p>
                </div>
            </div>
        </div>
    );
};

