                </div>
            </div>

            {/* POSICIÓN 3: EVOLUCIÓN MENSUAL DE LOGROS (ANCHO COMPLETO) */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2"><TrendingUp size={16} /> Evolución Mensual de Logros (Meta Cumplida)</h3>
                <p className="text-xs text-slate-500 mb-6">Conteo de documentos que alcanzaron la aprobación final en los últimos 12 meses móviles.</p>
                <div className="h-[350px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={evolutionData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                            <defs>
                                {Object.entries(TYPE_COLORS).map(([type, color]) => (
                                    <linearGradient key={type} id={`grad-${type.replace(' ', '')}`} x1="0" y1="0" x2="0" y2="1">
